	//Fin bacilloscopie


	//Debut supplementation en vitamine A
	if ((getValue('vitaminea_1.value') != '') ||
	(getValue('vitaminea_2.value') != '') ||
	(getValue('vitaminea_3.value') != '') ||
	(getValue('vitaminea_4.value') != '') ||
	(getValue('vitaminea_5.value') != '') ||
	(getValue('vitaminea_6.value') != '') ||
	(getValue('vitaminea_7.value') != '')) {
		setValue('vitaminea.value', '86339');
	}

	if ((getValue('fer_1.value') != '') ||
		(getValue('fer_2.value')!= '') ||
		(getValue('fer_3.value') != '') ||
		(getValue('fer_4.value') != '') ||
	 	(getValue('fer_5.value') !='') ||
	  	(getValue('fer_6.value') != '') ||
		(getValue('fer_7.value') != '')) {
		setValue('fer.value', '5843');
	}

	if ((getValue('iode_1.value') != '') ||
		(getValue('iode_2.value') != '') ||
