	  	(getValue('zinc_4.value') != '') ||
		(getValue('zinc_5.value') != '') ||
	 	(getValue('zinc_6.value') != '') ||
	  	(getValue('zinc_7.value') != '')) {
		setValue('zinc.value', '86672');
	}


	// Fin supplementation en vitamine A

	/*Validation for covid vaccine*/

	/*AstraZeneca*/
	if (getValue('astrazeneca_lotnum1.value') == '') {
	setValue('astrazeneca1.value', false);
	} else {
