jQuery(function() {
if (getValue('locationTypeValue.value') == '') {
setValue('locationTypeValue.value','Le site même');
}if (getValue('locationTypeValue.value') == '') {
setValue('locationTypeValue.value','Le site même');
}if ((getValue('locationTypeValue.value') == 'Point fixe ou satellite') || (getValue('locationTypeValue.value') == 'Clinique privée') || (getValue('locationTypeValue.value') == 'Maison privée') || (getValue('locationTypeValue.value') == 'Télémédecine')) {
jQuery('#locationValue').hide()
}

//jQuery('#locationType:not(:has(.required))').append('*');
jQuery('#locationTypeValue').on( 'change', function() {
if (getValue('locationTypeValue.value') == 'Le site même') {
jQuery('#locationValue').show();
//jQuery('#locationValue:not(:has(.required))').append('*');
} else if (getValue('locationTypeValue.value') == 'Site autre que celui du patient') {
jQuery('#locationValue').show();
//jQuery('#locationValue:not(:has(.required))').append('*');
} else {
jQuery('#locationValue').hide()
}
});
});

lookup.complexExpression:
	#set( $encounter = 0 )
	#set( $encounter = $fn.latestEncounter('709610ff-5e39-4a47-9c27-a60e740b0944') )
	#if( $encounter != 0 )		

	 <script type="text/javascript">
	 alert('Cette fiche, doit etre en un seul exemplaire');
			var url = window.location.search;
			var idurl=url.substring(url.lastIndexOf("=")+1);
				var cheminComplet = document.location.href;
				var longueur = window.location.protocol + "//" + window.location.host + "/";
				var souschaine=cheminComplet.substring(longueur.length,cheminComplet.indexOf("/",longueur.length));
				window.location = window.location.protocol + "//" + window.location.host + "/"+ souschaine +"/htmlformentryui/htmlform/editHtmlFormWithStandardUi.page?patientId=$encounter.patient.uuid&formUuid=$encounter.form.uuid&encounterId=$encounter.uuid";
	</script> 

#end
